#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <cuda_runtime.h>

#define TOL      (0.001)
#define STR_SIZE (256)
#define MAX_PD   (3.0e6)

#define PRECISION    0.001f
#define SPEC_HEAT_SI 1.75e6f
#define K_SI         100.0f

#define FACTOR_CHIP	0.5f

#define WG_SIZE_X (64)
#define WG_SIZE_Y (4)

extern "C" void readinput(float* v, int r, int c,int l,char*);
extern "C" void writeoutput(float* v,int r,int c,int l,char*);
extern "C" float accuracy(float* arr1, float* arr2, int len);
extern "C" void computeTempCPU(float* pIn, float *tIn, float *tOut, 
               int nx, int ny, int nz, float Cap,
               float Rx, float Ry, float Rz, 
               float dt, float amb_temp, int numiter);

extern "C" __global__ void hotspotOpt1(float *p, float* tIn, float *tOut, float sdc,
                            int nx, int ny, int nz,
                            float ce, float cw, 
                            float cn, float cs,
                            float ct, float cb, 
                            float cc);

void usage(int argc, char **argv)
{
  fprintf(stderr, "Usage: %s <-n rows/cols> <-l layers> <-i iterations> <-f powerFile tempFile outputFile>\n", argv[0]);
  fprintf(stderr, "\t<rows/cols>  - number of rows/cols in the grid (positive integer)\n");
  fprintf(stderr, "\t<layers>  - number of layers in the grid (positive integer)\n");
  fprintf(stderr, "\t<iteration> - number of iterations\n");
  fprintf(stderr, "\t<powerFile>  - name of the file containing the initial power values of each cell\n");
  fprintf(stderr, "\t<tempFile>  - name of the file containing the initial temperature values of each cell\n");
  fprintf(stderr, "\t<outputFile> - output file\n");
  exit(1);
}

int main(int argc, char** argv)
{
    char *pfile = NULL, *tfile = NULL, *ofile = NULL;
    int iterations = 0;
    int numCols    = 0;
    int numRows    = 0;
    int layers     = 0;

    int cur_arg;
	for (cur_arg = 1; cur_arg<argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-h") == 0) {
			usage(argc, argv);
        }
        else if (strcmp(argv[cur_arg], "-n") == 0) {
            if (argc >= cur_arg + 1) {
                numCols = numRows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-l") == 0) {
            if (argc >= cur_arg + 1) {
                layers = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-i") == 0) {
            if (argc >= cur_arg + 1) {
                iterations = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-f") == 0) {
            if (argc >= cur_arg + 3) {
                pfile = argv[cur_arg+1];
                tfile = argv[cur_arg+2];
                ofile = argv[cur_arg+3];
                cur_arg += 3;
            }
        }
    }

	if (numCols == 0 || layers == 0 || iterations == 0 || pfile == NULL || tfile == NULL || ofile == NULL) {
		usage(argc, argv);
	}

  float t_chip      = 0.0005f;
  float chip_height = 0.016f;
  float chip_width  = 0.016f;
  float amb_temp    = 80.0f;

  float dx         = chip_height/numRows;
  float dy         = chip_width/numCols;
  float dz         = t_chip/layers;

  float Cap        = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * dx * dy;
  float Rx         = dy / (2.0f * K_SI * t_chip * dx);
  float Ry         = dx / (2.0f * K_SI * t_chip * dy);
  float Rz         = dz / (K_SI * dx * dy);

  float max_slope  = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
  float dt         = PRECISION / max_slope;

  float ce, cw, cn, cs, ct, cb, cc;
  float stepDivCap = dt / Cap;
  ce               = cw                                              = stepDivCap/ Rx;
  cn               = cs                                              = stepDivCap/ Ry;
  ct               = cb                                              = stepDivCap/ Rz;

  cc               = 1.0f - (2.0f*ce + 2.0f*cn + 3.0f*ct);

  int size = numCols * numRows * layers;
  float* tIn      = (float*) calloc(size,sizeof(float));
  float* pIn      = (float*) calloc(size,sizeof(float));
  float* tempCopy = (float*)malloc(size * sizeof(float));
  float* tempOut  = (float*) calloc(size,sizeof(float));
  if (!tIn || !pIn || !tempCopy || !tempOut) {
      fprintf(stderr, "Memory allocation failed\n");
      return 1;
  }

  readinput(tIn,numRows, numCols, layers, tfile);
  readinput(pIn,numRows, numCols, layers, pfile);

  memcpy(tempCopy,tIn, size * sizeof(float));

  float *d_tIn, *d_pIn, *d_tempOut;
  cudaError_t err;

  err = cudaMalloc((void**)&d_tIn, size * sizeof(float));
  if (err != cudaSuccess) { fprintf(stderr, "cudaMalloc d_tIn failed\n"); return 1; }
  err = cudaMalloc((void**)&d_pIn, size * sizeof(float));
  if (err != cudaSuccess) { fprintf(stderr, "cudaMalloc d_pIn failed\n"); return 1; }
  err = cudaMalloc((void**)&d_tempOut, size * sizeof(float));
  if (err != cudaSuccess) { fprintf(stderr, "cudaMalloc d_tempOut failed\n"); return 1; }

  err = cudaMemcpy(d_tIn, tIn, size * sizeof(float), cudaMemcpyHostToDevice);
  if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy d_tIn failed\n"); return 1; }
  err = cudaMemcpy(d_pIn, pIn, size * sizeof(float), cudaMemcpyHostToDevice);
  if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy d_pIn failed\n"); return 1; }
  err = cudaMemcpy(d_tempOut, tempOut, size * sizeof(float), cudaMemcpyHostToDevice);
  if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy d_tempOut failed\n"); return 1; }

  dim3 block(WG_SIZE_X, WG_SIZE_Y);
  dim3 grid((numCols + block.x - 1) / block.x, (numRows + block.y - 1) / block.y);

  float *d_tIn_current = d_tIn;
  float *d_tOut_current = d_tempOut;

  for(int j = 0; j < iterations; j++)
  {
      hotspotOpt1<<<grid, block>>>(d_pIn, d_tIn_current, d_tOut_current, stepDivCap,
                                   numCols, numRows, layers,
                                   ce, cw, cn, cs, ct, cb, cc);
      err = cudaGetLastError();
      if (err != cudaSuccess) {
          fprintf(stderr, "Kernel launch failed: %s\n", cudaGetErrorString(err));
          return 1;
      }
      err = cudaDeviceSynchronize();
      if (err != cudaSuccess) {
          fprintf(stderr, "cudaDeviceSynchronize failed: %s\n", cudaGetErrorString(err));
          return 1;
      }
      // Swap pointers
      float* temp = d_tIn_current;
      d_tIn_current = d_tOut_current;
      d_tOut_current = temp;
  }

  // After last iteration, d_tIn_current points to latest output
  err = cudaMemcpy(tempOut, d_tIn_current, size * sizeof(float), cudaMemcpyDeviceToHost);
  if (err != cudaSuccess) { fprintf(stderr, "cudaMemcpy device to host failed\n"); return 1; }

  cudaFree(d_tIn);
  cudaFree(d_pIn);
  cudaFree(d_tempOut);

  float* answer = (float*)calloc(size, sizeof(float));
  if (!answer) {
      fprintf(stderr, "Memory allocation failed\n");
      return 1;
  }
  computeTempCPU(pIn, tempCopy, answer, numCols, numRows, layers, Cap, Rx, Ry, Rz, dt, amb_temp, iterations);
  float acc = accuracy(tempOut,answer,numRows*numCols*layers);
  printf("Accuracy: %e\n",acc);

  writeoutput(tempOut,numRows,numCols,layers,ofile);

  free(tIn);
  free(pIn);
  free(tempCopy);
  free(tempOut);
  free(answer);

  return 0;
}
